1	import {
2		Injectable,
3		Logger,
4		BadRequestException,
5		HttpException,
6		InternalServerErrorException,
7	} from '@nestjs/common';
8	
9	import { NewrelicService } from '@modules/newrelic/newrelic.service';
10	
11	import { RealLifeTestDto, HardTaskDto, Product } from '@dto/load-test/load-test.dto';
12	
13	@Injectable()
14	export class LoadTestService {
15		private readonly logger = new Logger(LoadTestService.name);
16		private readonly module = LoadTestService.name;
17	
18		constructor(private readonly newrelicService: NewrelicService) {}
19	
20		async realLifeTest(query: RealLifeTestDto): Promise<Product[]> {
21			const start = process.hrtime();
22	
23			if (query.throwError) {
24				this.logger.error('Intentional error via throwError');
25				throw new BadRequestException('Requested error from the real-life test endpoint');
26			}
27	
28			try {
29				const products = this.generateRandomProducts(5);
30	
31				const elapsedMs = this.getElapsedMs(start);
32				this.newrelicService.recordMetric({
33					module: this.module,
34					metricName: 'realLifeTest/ResponseTime',
35					value: elapsedMs,
36				});
37				this.newrelicService.incrementMetric({
38					module: this.module,
39					metricName: 'realLifeTest/CallCount',
40				});
41				this.logger.log(`realLifeTest succeeded in ${elapsedMs.toFixed(2)}ms`);
42	
43				return await Promise.resolve(products);
44			} catch (err: unknown) {
45				this.newrelicService.incrementMetric({
46					module: this.module,
47					metricName: 'realLifeTest/ErrorCount',
48				});
49	
50				if (err instanceof HttpException) {
51					throw err;
52				}
53	
54				const message = err instanceof Error ? err.message : String(err);
55				this.logger.error(
56					`realLifeTest error: ${message}`,
57					err instanceof Error ? err.stack : undefined,
58				);
59				throw new InternalServerErrorException('Unexpected error during real-life test');
60			}
61		}
62	
63		async calculatePi(
64			query: HardTaskDto,
65		): Promise<{ pi: string; executionTimeMs: number }> {
66			const start = process.hrtime();
67	
68			if (query.throwError) {
69				this.logger.error('Intentional error via throwError');
70				throw new BadRequestException('Requested error from the hard task endpoint');
71			}
72	
73			try {
74				const iterations = 10_000;
75				let pi = 3.0;
76				let sign = 1;
77				for (let i = 2; i <= 2 * iterations; i += 2) {
78					pi += sign * (4 / (i * (i + 1) * (i + 2)));
79					sign *= -1;
80				}
81				const piString = pi.toFixed(49);
82	
83				const executionTimeMs = this.getElapsedMs(start);
84				this.newrelicService.recordMetric({
85					module: this.module,
86					metricName: 'calculatePi/ResponseTime',
87					value: executionTimeMs,
88				});
89				this.newrelicService.incrementMetric({
90					module: this.module,
91					metricName: 'calculatePi/CallCount',
92				});
93				this.logger.log(`calculatePi done in ${executionTimeMs.toFixed(2)}ms: ${piString}`);
94	
95				return await Promise.resolve({ pi: piString, executionTimeMs });
96			} catch (err: unknown) {
97				this.newrelicService.incrementMetric({
98					module: this.module,
99					metricName: 'calculatePi/ErrorCount',
100				});
101	
102				if (err instanceof HttpException) {
103					throw err;
104				}
105	
106				const message = err instanceof Error ? err.message : String(err);
107				this.logger.error(
108					`calculatePi error: ${message}`,
109					err instanceof Error ? err.stack : undefined,
110				);
111				throw new InternalServerErrorException('Unexpected error during Pi calculation');
112			}
113		}
114	
115		async simulateThirdPartyCall(query: {
116			throwError?: boolean;
117		}): Promise<{ response: string; executionTimeMs: number }> {
118			const start = process.hrtime();
119	
120			if (query.throwError) {
121				this.logger.error('Intentional error via throwError in third-party simulation');
122				throw new BadRequestException(
123					'Requested error from the third-party simulation endpoint',
124				);
125			}
126	
127			try {
128				const delay = Math.floor(Math.random() * 21) + 80;
129				await new Promise((r) => setTimeout(r, delay));
130	
131				const executionTimeMs = this.getElapsedMs(start);
132				this.newrelicService.recordMetric({
133					module: this.module,
134					metricName: 'thirdPartyCall/ResponseTime',
135					value: executionTimeMs,
136				});
137				this.newrelicService.incrementMetric({
138					module: this.module,
139					metricName: 'thirdPartyCall/CallCount',
140				});
141				this.logger.log(`simulateThirdPartyCall done in ${executionTimeMs.toFixed(2)}ms`);
142	
143				return {
144					response: `Third-party service response with delay of ${delay}ms`,
145					executionTimeMs,
146				};
147			} catch (err: unknown) {
148				this.newrelicService.incrementMetric({
149					module: this.module,
150					metricName: 'thirdPartyCall/ErrorCount',
151				});
152	
153				if (err instanceof HttpException) {
154					throw err;
155				}
156	
157				const message = err instanceof Error ? err.message : String(err);
158				this.logger.error(
159					`simulateThirdPartyCall error: ${message}`,
160					err instanceof Error ? err.stack : undefined,
161				);
162				throw new InternalServerErrorException(
163					'Unexpected error during third-party call simulation',
164				);
165			}
166		}
167	
168		private getElapsedMs(start: [number, number]): number {
169			const [s, ns] = process.hrtime(start);
170			return s * 1000 + ns / 1_000_000;
171		}
172	
173		private generateRandomProducts(count: number): Product[] {
174			return Array.from({ length: count }, () => this.generateRandomProduct());
175		}
176	
177		private generateRandomProduct(): Product {
178			const product_id = 999600 + Math.floor(Math.random() * 100);
179			const decoration_methods = [
180				'embroidery',
181				'screen printing',
182				'digital printing',
183				'heat transfer',
184			];
185			const manufacturers = ['Sanmar', 'Gildan', 'Hanes', 'Nike', 'Adidas', 'Carhartt'];
186			const statuses = ['active', 'inactive', 'deprecated'];
187			const style_types = ['apparel', 'headwear', 'bags', 'accessories'];
188			const product_types = ['Unisex', 'Mens', 'Womens', 'Youth'];
189			const broad_categories = [
190				'Workwear & Uniforms',
191				'Business & Occupations',
192				'Featured Brands',
193				'Embroidery',
194				'Jackets',
195				'T-shirts',
196				'Sweatshirts & Hoodies',
197			];
198			const sub_categories = [
199				'Construction',
200				'Home Services',
201				'Contractors & Landscapers',
202				'Carhartt',
203				'Outerwear',
204				'Work Jackets',
205				'All Workwear & Uniforms',
206				'Tall Jackets',
207				'All Jackets',
208				'Workwear',
209				'All Embroidery',
210			];
211			const colors = [
212				{ name: 'Black', id: 100 + Math.floor(Math.random() * 900) },
213				{ name: 'White', id: 100 + Math.floor(Math.random() * 900) },
214				{ name: 'Red', id: 100 + Math.floor(Math.random() * 900) },
215				{ name: 'Blue', id: 100 + Math.floor(Math.random() * 900) },
216				{ name: 'Green', id: 100 + Math.floor(Math.random() * 900) },
217				{ name: 'Carhartt Brown', id: 100 + Math.floor(Math.random() * 900) },
218			];
219	
220			const getRandomItem = <T>(arr: T[]): T => {
221				if (!arr.length) throw new Error('Cannot pick from empty array');
222				const item = arr[Math.floor(Math.random() * arr.length)];
223				if (!item) throw new Error('Item is undefined');
224				return item;
225			};
226	
227			const randomProduct: Product = {
228				product_id,
229				decoration_method: getRandomItem(decoration_methods),
230				features:
231					'* Quilted nylon lined sleeves for easy on-and-off\r\n* Pleated bi-swing back for additional range of motion\r\n* Longer length for more coverage\r\n* Left chest pocket with zipper closure',
232				general_comments:
233					'Classic Carhartt style meets Carhartt durability in this coat which features cotton duck fabric for a tough exterior and a soft sherpa lining for warmth and added coziness.',
234				manufacturer: getRandomItem(manufacturers),
235				minimum_quantity: Math.floor(Math.random() * 10) + 1,
236				name: `${getRandomItem(manufacturers)} ${getRandomItem(product_types)} Product #${Math.floor(Math.random() * 1000)}`,
237				rating_count: Math.floor(Math.random() * 100),
238				rating_score: (Math.random() * 5).toFixed(1),
239				sizes: ['S', 'M', 'L', 'XL', 'XXL'].slice(0, Math.floor(Math.random() * 5) + 1),
240				status: getRandomItem(statuses),
241				style_type: getRandomItem(style_types),
242				product_type: getRandomItem(product_types),
243				style_card_image_url: `https://mms-images.staging.customink.com/mms/images/catalog/${this.randomString(32)}/styles/${product_id}/catalog_detail_image_medium.jpg`,
244				broad_category_names: this.getRandomSubset(
245					broad_categories,
246					Math.floor(Math.random() * 5) + 1,
247				),
248				sub_category_names: this.getRandomSubset(
249					sub_categories,
250					Math.floor(Math.random() * 5) + 1,
251				),
252				turn_time: Math.floor(Math.random() * 20) + 5,
253				rush_turn_time: Math.floor(Math.random() * 10) + 1,
254				default_unit_prices: this.generateRandomPrices(),
255				link: {
256					name: `Product #${product_id}`,
257					path: `/products/workwear-uniforms/work-jackets/product-${product_id}`,
258				},
259				colors: this.getRandomSubset(colors, Math.floor(Math.random() * 3) + 1),
260				objectID: product_id.toString(),
261			};
262	
263			return randomProduct;
264		}
265	
266		private getRandomSubset<T>(arr: T[], count: number): T[] {
267			if (!arr.length) return [];
268			const safeCount = Math.min(Math.max(count, 1), arr.length);
269			const copy = [...arr];
270			const result: T[] = [];
271			while (result.length < safeCount) {
272				const idx = Math.floor(Math.random() * copy.length);
273				const item = copy.splice(idx, 1)[0];
274				if (!item) result.push(item as T);
275			}
276			return result;
277		}
278	
279		private randomString(length: number): string {
280			const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
281			return Array.from({ length })
282				.map(() => chars[Math.floor(Math.random() * chars.length)])
283				.join('');
284		}
285	
286		private generateRandomPrices(): {
287			algorithm: string;
288			quantity: number;
289			price: string;
290		}[] {
291			const algorithms = ['default-2022-03-24', 'plus_5-2024-04-30', 'minus_5-2024-04-30'];
292			const quantities = [15, 20, 25, 50, 100, 500];
293			const prices: { algorithm: string; quantity: number; price: string }[] = [];
294	
295			for (const algorithm of algorithms) {
296				for (const quantity of quantities) {
297					if (Math.random() < 0.5) {
298						const base = 200 + Math.random() * 50;
299						const adjusted = base * (1 - quantity / 1000);
300						prices.push({
301							algorithm,
302							quantity,
303							price: adjusted.toFixed(2),
304						});
305					}
306				}
307			}
308	
309			return prices;
310		}
311	}
