1	import type { EventEmitter } from 'events';
2	
3	type ProcessorFunction = ({
4		userContext,
5		events,
6		done,
7	}: {
8		userContext: { vars: Record<string, unknown> };
9		events: EventEmitter;
10		done: () => void;
11	}) => void;
12	
13	export interface Color {
14		name: string;
15		id: number;
16	}
17	
18	export interface Link {
19		name: string;
20		path: string;
21	}
22	
23	export interface Price {
24		algorithm: string;
25		quantity: number;
26		price: string;
27	}
28	
29	export interface Product {
30		product_id: number;
31		decoration_method: string;
32		features: string;
33		general_comments: string;
34		manufacturer: string;
35		minimum_quantity: number;
36		name: string;
37		rating_count: number;
38		rating_score: string;
39		sizes: string[];
40		status: 'active' | 'inactive' | 'deprecated';
41		style_type: 'apparel' | 'headwear' | 'bags' | 'accessories';
42		product_type: 'Unisex' | 'Mens' | 'Womens' | 'Youth';
43		style_card_image_url: string;
44		broad_category_names: string[];
45		sub_category_names: string[];
46		turn_time: number;
47		rush_turn_time: number;
48		default_unit_prices: Price[];
49		link: Link;
50		colors: Color[];
51		objectID: string;
52	}
53	
54	export const generateName: ProcessorFunction = ({ userContext, done }) => {
55		const names = [
56			'John',
57			'Mary',
58			'Robert',
59			'Patricia',
60			'Michael',
61			'Jennifer',
62			'William',
63			'Linda',
64			'David',
65			'Elizabeth',
66			'Richard',
67			'Barbara',
68			'Joseph',
69			'Susan',
70			'Thomas',
71			'Jessica',
72		];
73		userContext.vars['name'] = randomChoice({ arr: names });
74		done();
75	};
76	
77	export const randomThrowError: ProcessorFunction = ({ userContext, done }) => {
78		userContext.vars['throwError'] = Math.random() < 0.1;
79		done();
80	};
81	
82	export const generateProductArray: ProcessorFunction = ({ userContext, done }) => {
83		const products: Product[] = [];
84	
85		for (let i = 0; i < 30; i++) {
