93				features: generateFeaturesList(),
94				general_comments:
95					'Classic Carhartt style meets Carhartt durability in this coat which features cotton duck fabric for a tough exterior and a soft sherpa lining for warmth and added coziness.',
96				manufacturer: randomChoice({
97					arr: ['Sanmar', 'Gildan', 'Hanes', 'Nike', 'Adidas', 'Carhartt'],
98				}),
99				minimum_quantity: Math.floor(Math.random() * 10) + 1,
100				name: `${randomChoice({ arr: ['Carhartt', 'Nike', 'Adidas'] })} ${randomChoice({
101					arr: ['Tall', 'Short', 'Regular'],
102				})} ${randomChoice({ arr: ['Washed Duck', 'Cotton', 'Polyester'] })} ${randomChoice(
103					{
104						arr: ['Sherpa-Lined Coat', 'T-Shirt', 'Hoodie'],
105					},
106				)}`,
107				rating_count: Math.floor(Math.random() * 100),
108				rating_score: (Math.random() * 5).toFixed(1),
109				sizes: generateRandomSubset({
110					arr: ['XS', 'S', 'M', 'L', 'XL', 'XXL', 'XXXL', 'LT', 'XLT', 'XXLT', 'XXXLT'],
111					count: Math.floor(Math.random() * 5) + 1,
112				}),
113				status: randomChoice({ arr: ['active', 'inactive', 'deprecated'] }),
114				style_type: randomChoice({ arr: ['apparel', 'headwear', 'bags', 'accessories'] }),
115				product_type: randomChoice({ arr: ['Unisex', 'Mens', 'Womens', 'Youth'] }),
116				style_card_image_url: `https://mms-images.staging.customink.com/mms/images/catalog/${randomString({ length: 32 })}/styles/${productId}/catalog_detail_image_medium.jpg`,
117				broad_category_names: generateRandomSubset({
118					arr: [
119						'Workwear & Uniforms',
120						'Business & Occupations',
121						'Featured Brands',
122						'Embroidery',
123						'Jackets',
124						'T-shirts',
125						'Sweatshirts & Hoodies',
126					],
127					count: Math.floor(Math.random() * 5) + 1,
128				}),
129				sub_category_names: generateRandomSubset({
130					arr: [
131						'Construction',
132						'Home Services',
133						'Contractors & Landscapers',
134						'Carhartt',
135						'Outerwear',
136						'Work Jackets',
137						'All Workwear & Uniforms',
138						'Tall Jackets',
139						'All Jackets',
140						'Workwear',
141						'All Embroidery',
142					],
143					count: Math.floor(Math.random() * 5) + 1,
144				}),
145				turn_time: Math.floor(Math.random() * 20) + 5,
146				rush_turn_time: Math.floor(Math.random() * 10) + 1,
147				default_unit_prices: generatePrices(),
148				link: {
149					name: `Product #${productId}`,
150					path: `/products/workwear-uniforms/work-jackets/product-${productId}`,
151				},
152				colors: generateRandomSubset({
153					arr: [
154						{ name: 'Black', id: 100 + Math.floor(Math.random() * 900) },
155						{ name: 'White', id: 100 + Math.floor(Math.random() * 900) },
156						{ name: 'Red', id: 100 + Math.floor(Math.random() * 900) },
157						{ name: 'Blue', id: 100 + Math.floor(Math.random() * 900) },
158						{ name: 'Green', id: 100 + Math.floor(Math.random() * 900) },
159						{ name: 'Carhartt Brown', id: 100 + Math.floor(Math.random() * 900) },
160					],
161					count: Math.floor(Math.random() * 3) + 1,
162				}),
163				objectID: productId.toString(),
164			});
165		}
166	
167		userContext.vars['products'] = products;
168		done();
169	};
170	
171	/** Helpers */
172	function randomChoice<T>({ arr }: { arr: T[] }): T {
173		return arr[Math.floor(Math.random() * arr.length)] as T;
174	}
175	
176	function generateRandomSubset<T>({ arr, count }: { arr: T[]; count: number }): T[] {
177		const shuffled = [...arr].sort(() => 0.5 - Math.random());
178		return shuffled.slice(0, count);
179	}
180	
181	function randomString({ length }: { length: number }): string {
182		const characters = 'abcdefghijklmnopqrstuvwxyz0123456789';
183		let result = '';
184		for (let i = 0; i < length; i++) {
185			result += characters.charAt(Math.floor(Math.random() * characters.length));
186		}
187		return result;
188	}
189	
190	function generateFeaturesList(): string {
191		const features = [
192			'Quilted nylon lined sleeves for easy on-and-off',
193			'Pleated bi-swing back for additional range of motion',
194			'Longer length for more coverage',
195			'Left chest pocket with zipper closure',
