import {
	Injectable,
	Logger,
	BadRequestException,
	HttpException,
	InternalServerErrorException,
} from '@nestjs/common';

import { NewrelicService } from '@modules/newrelic/newrelic.service';

import { RealLifeTestDto, HardTaskDto, Product } from '@dto/load-test/load-test.dto';

@Injectable()
export class LoadTestService {
	private readonly logger = new Logger(LoadTestService.name);
	private readonly module = LoadTestService.name;

	constructor(private readonly newrelicService: NewrelicService) {}

	async realLifeTest({ query }: { query: RealLifeTestDto }): Promise<Product[]> {
		const start = process.hrtime();

		if (query.throwError) {
			this.logger.error('Intentional error via throwError');
			throw new BadRequestException('Requested error from the real-life test endpoint');
		}

		try {
			const products = this.generateRandomProducts({ count: 5 });

			const elapsedMs = this.getElapsedMs({ start });
			this.newrelicService.recordMetric({
				module: this.module,
				metricName: 'realLifeTest/ResponseTime',
				value: elapsedMs,
			});
			this.newrelicService.incrementMetric({
				module: this.module,
				metricName: 'realLifeTest/CallCount',
			});
			this.logger.log(`realLifeTest succeeded in ${elapsedMs.toFixed(2)}ms`);

			return await Promise.resolve(products);
		} catch (err: unknown) {
			this.newrelicService.incrementMetric({
				module: this.module,
				metricName: 'realLifeTest/ErrorCount',
			});

			if (err instanceof HttpException) {
				throw err;
			}

			const message = err instanceof Error ? err.message : String(err);
			this.logger.error(
				`realLifeTest error: ${message}`,
				err instanceof Error ? err.stack : undefined,
			);
			throw new InternalServerErrorException('Unexpected error during real-life test');
		}
	}

	async calculatePi({
		query,
	}: {
		query: HardTaskDto;
	}): Promise<{ pi: string; executionTimeMs: number }> {
		const start = process.hrtime();

		if (query.throwError) {
			this.logger.error('Intentional error via throwError');
			throw new BadRequestException('Requested error from the hard task endpoint');
		}

		try {
			const iterations = 10_000;
			let pi = 3.0;
			let sign = 1;
			for (let i = 2; i <= 2 * iterations; i += 2) {
				pi += sign * (4 / (i * (i + 1) * (i + 2)));
				sign *= -1;
			}
			const piString = pi.toFixed(49);

			const executionTimeMs = this.getElapsedMs({ start });
			this.newrelicService.recordMetric({
				module: this.module,
				metricName: 'calculatePi/ResponseTime',
				value: executionTimeMs,
			});
			this.newrelicService.incrementMetric({
				module: this.module,
				metricName: 'calculatePi/CallCount',
			});
			this.logger.log(`calculatePi done in ${executionTimeMs.toFixed(2)}ms: ${piString}`);

			return await Promise.resolve({ pi: piString, executionTimeMs });
		} catch (err: unknown) {
			this.newrelicService.incrementMetric({
				module: this.module,
				metricName: 'calculatePi/ErrorCount',
			});

			if (err instanceof HttpException) {
				throw err;
			}

			const message = err instanceof Error ? err.message : String(err);
			this.logger.error(
				`calculatePi error: ${message}`,
				err instanceof Error ? err.stack : undefined,
			);
			throw new InternalServerErrorException('Unexpected error during Pi calculation');
		}
	}

	async simulateThirdPartyCall({
		query,
	}: {
		query: { throwError?: boolean };
	}): Promise<{ response: string; executionTimeMs: number }> {
		const start = process.hrtime();

		if (query.throwError) {
			this.logger.error('Intentional error via throwError in third-party simulation');
			throw new BadRequestException(
				'Requested error from the third-party simulation endpoint',
			);
		}

		try {
			const delay = Math.floor(Math.random() * 21) + 80;
			await new Promise((r) => setTimeout(r, delay));

			const executionTimeMs = this.getElapsedMs({ start });
			this.newrelicService.recordMetric({
				module: this.module,
				metricName: 'thirdPartyCall/ResponseTime',
				value: executionTimeMs,
			});
			this.newrelicService.incrementMetric({
				module: this.module,
				metricName: 'thirdPartyCall/CallCount',
			});
			this.logger.log(`simulateThirdPartyCall done in ${executionTimeMs.toFixed(2)}ms`);

			return {
				response: `Third-party service response with delay of ${delay}ms`,
				executionTimeMs,
			};
		} catch (err: unknown) {
			this.newrelicService.incrementMetric({
				module: this.module,
				metricName: 'thirdPartyCall/ErrorCount',
			});

			if (err instanceof HttpException) {
				throw err;
			}

			const message = err instanceof Error ? err.message : String(err);
			this.logger.error(
				`simulateThirdPartyCall error: ${message}`,
				err instanceof Error ? err.stack : undefined,
			);
			throw new InternalServerErrorException(
				'Unexpected error during third-party call simulation',
			);
		}
	}

	private getElapsedMs({ start }: { start: [number, number] }): number {
		const [s, ns] = process.hrtime(start);
		return s * 1000 + ns / 1_000_000;
	}

	private generateRandomProducts({ count }: { count: number }): Product[] {
		return Array.from({ length: count }, () => this.generateRandomProduct());
	}

	private generateRandomProduct(): Product {
		const product_id = 999600 + Math.floor(Math.random() * 100);
		const decoration_methods = [
			'embroidery',
			'screen printing',
			'digital printing',
			'heat transfer',
		];
		const manufacturers = ['Sanmar', 'Gildan', 'Hanes', 'Nike', 'Adidas', 'Carhartt'];
		const statuses = ['active', 'inactive', 'deprecated'];
		const style_types = ['apparel', 'headwear', 'bags', 'accessories'];
		const product_types = ['Unisex', 'Mens', 'Womens', 'Youth'];
		const broad_categories = [
			'Workwear & Uniforms',
			'Business & Occupations',
			'Featured Brands',
			'Embroidery',
			'Jackets',
			'T-shirts',
			'Sweatshirts & Hoodies',
		];
		const sub_categories = [
			'Construction',
			'Home Services',
			'Contractors & Landscapers',
			'Carhartt',
			'Outerwear',
			'Work Jackets',
			'All Workwear & Uniforms',
			'Tall Jackets',
			'All Jackets',
			'Workwear',
			'All Embroidery',
		];
		const colors = [
			{ name: 'Black', id: 100 + Math.floor(Math.random() * 900) },
			{ name: 'White', id: 100 + Math.floor(Math.random() * 900) },
			{ name: 'Red', id: 100 + Math.floor(Math.random() * 900) },
			{ name: 'Blue', id: 100 + Math.floor(Math.random() * 900) },
			{ name: 'Green', id: 100 + Math.floor(Math.random() * 900) },
			{ name: 'Carhartt Brown', id: 100 + Math.floor(Math.random() * 900) },
		];

		const getRandomItem = <T>({ arr }: { arr: T[] }): T => {
			if (!arr.length) throw new Error('Cannot pick from empty array');
			const item = arr[Math.floor(Math.random() * arr.length)];
			if (!item) throw new Error('Item is undefined');
			return item;
		};

		const randomProduct: Product = {
			product_id,
			decoration_method: getRandomItem({ arr: decoration_methods }),
			features:
				'* Quilted nylon lined sleeves for easy on-and-off\r\n* Pleated bi-swing back for additional range of motion\r\n* Longer length for more coverage\r\n* Left chest pocket with zipper closure',
			general_comments:
				'Classic Carhartt style meets Carhartt durability in this coat which features cotton duck fabric for a tough exterior and a soft sherpa lining for warmth and added coziness.',
			manufacturer: getRandomItem({ arr: manufacturers }),
			minimum_quantity: Math.floor(Math.random() * 10) + 1,
			name: `${getRandomItem({ arr: manufacturers })} ${getRandomItem({ arr: product_types })} Product #${Math.floor(Math.random() * 1000)}`,
			rating_count: Math.floor(Math.random() * 100),
			rating_score: (Math.random() * 5).toFixed(1),
			sizes: ['S', 'M', 'L', 'XL', 'XXL'].slice(0, Math.floor(Math.random() * 5) + 1),
			status: getRandomItem({ arr: statuses }),
			style_type: getRandomItem({ arr: style_types }),
			product_type: getRandomItem({ arr: product_types }),
			style_card_image_url: `https://mms-images.staging.customink.com/mms/images/catalog/${this.randomString({ length: 32 })}/styles/${product_id}/catalog_detail_image_medium.jpg`,
			broad_category_names: this.getRandomSubset({
				arr: broad_categories,
				count: Math.floor(Math.random() * 5) + 1,
			}),
			sub_category_names: this.getRandomSubset({
				arr: sub_categories,
				count: Math.floor(Math.random() * 5) + 1,
			}),
			turn_time: Math.floor(Math.random() * 20) + 5,
			rush_turn_time: Math.floor(Math.random() * 10) + 1,
			default_unit_prices: this.generateRandomPrices(),
			link: {
				name: `Product #${product_id}`,
				path: `/products/workwear-uniforms/work-jackets/product-${product_id}`,
			},
			colors: this.getRandomSubset({
				arr: colors,
				count: Math.floor(Math.random() * 3) + 1,
			}),
			objectID: product_id.toString(),
		};

		return randomProduct;
	}

	private getRandomSubset<T>({ arr, count }: { arr: T[]; count: number }): T[] {
		if (!arr.length) return [];
		const safeCount = Math.min(Math.max(count, 1), arr.length);
		const copy = [...arr];
		const result: T[] = [];
		while (result.length < safeCount) {
			const idx = Math.floor(Math.random() * copy.length);
			const item = copy.splice(idx, 1)[0];
			if (!item) result.push(item as T);
		}
		return result;
	}

	private randomString({ length }: { length: number }): string {
		const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
		return Array.from({ length })
			.map(() => chars[Math.floor(Math.random() * chars.length)])
			.join('');
	}

	private generateRandomPrices(): {
		algorithm: string;
		quantity: number;
		price: string;
	}[] {
		const algorithms = ['default-2022-03-24', 'plus_5-2024-04-30', 'minus_5-2024-04-30'];
		const quantities = [15, 20, 25, 50, 100, 500];
		const prices: { algorithm: string; quantity: number; price: string }[] = [];

		for (const algorithm of algorithms) {
			for (const quantity of quantities) {
				if (Math.random() < 0.5) {
					const base = 200 + Math.random() * 50;
					const adjusted = base * (1 - quantity / 1000);
					prices.push({
						algorithm,
						quantity,
						price: adjusted.toFixed(2),
					});
				}
			}
		}

		return prices;
	}
}

